// ══════════════════════════════════════════
// SOUND ENGINE
// ══════════════════════════════════════════
(function initSounds() {
  const ctx = new (window.AudioContext || window.webkitAudioContext)();

  function resume() { if (ctx.state === 'suspended') ctx.resume(); }

  function osc(type, freq, gainVal, duration, when) {
    const o = ctx.createOscillator(), g = ctx.createGain();
    o.connect(g); g.connect(ctx.destination);
    o.type = type; o.frequency.value = freq;
    g.gain.setValueAtTime(gainVal, when);
    g.gain.exponentialRampToValueAtTime(0.0001, when + duration);
    o.start(when); o.stop(when + duration + 0.05);
  }

  function noise(cutoff, gainVal, duration, when) {
    const buf = ctx.createBuffer(1, ctx.sampleRate * duration, ctx.sampleRate);
    const ch  = buf.getChannelData(0);
    for (let i = 0; i < ch.length; i++) ch[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / ch.length, 2.5);
    const src = ctx.createBufferSource(), filt = ctx.createBiquadFilter(), g = ctx.createGain();
    filt.type = 'lowpass'; filt.frequency.value = cutoff;
    src.buffer = buf; src.connect(filt); filt.connect(g); g.connect(ctx.destination);
    g.gain.setValueAtTime(gainVal, when);
    g.gain.exponentialRampToValueAtTime(0.0001, when + duration);
    src.start(when);
  }

  /* ── Action sounds ─────────────────────────────── */

  // Keep: upbeat ascending chime G5 → B5 → D6
  window.playKeepSound = function() {
    resume(); const t = ctx.currentTime;
    osc('sine', 784,  0.18, 0.12, t);
    osc('sine', 988,  0.15, 0.12, t + 0.07);
    osc('sine', 1175, 0.12, 0.20, t + 0.14);
  };

  // Delete: downward thud D4 → A3 + low noise
  window.playDeleteSound = function() {
    resume(); const t = ctx.currentTime;
    osc('triangle', 294, 0.22, 0.14, t);
    osc('triangle', 220, 0.18, 0.20, t + 0.09);
    noise(120, 0.4, 0.18, t + 0.04);
  };

  // Undo: quick rewind blip
  window.playUndoSound = function() {
    resume(); const t = ctx.currentTime;
    osc('sine', 660, 0.13, 0.10, t);
    osc('sine', 523, 0.10, 0.12, t + 0.07);
  };

  /* ── Download / export sounds (upbeat) ────────── */
  // Positive "confirm" ding: C5 → E5 → G5
  window.playDownloadSound = function() {
    resume(); const t = ctx.currentTime;
    osc('sine', 523, 0.16, 0.10, t);
    osc('sine', 659, 0.14, 0.10, t + 0.06);
    osc('sine', 784, 0.12, 0.18, t + 0.12);
    // soft sparkle on top
    osc('sine', 1047, 0.06, 0.14, t + 0.18);
  };

  /* ── Export list sound (downbeat-ish, neutral) ── */
  // Soft "page turn" swoosh: mid drop
  window.playExportListSound = function() {
    resume(); const t = ctx.currentTime;
    osc('sine', 440, 0.14, 0.12, t);
    osc('sine', 349, 0.12, 0.16, t + 0.08);
    noise(600, 0.12, 0.15, t);
  };

  /* ── Shell script sound (downbeat, purposeful) ── */
  // "Terminal" feel: two low square blips
  window.playShellSound = function() {
    resume(); const t = ctx.currentTime;
    osc('square', 220, 0.10, 0.06, t);
    osc('square', 165, 0.08, 0.10, t + 0.08);
    noise(300, 0.18, 0.12, t + 0.06);
  };

  /* ── Start over (downbeat, clearing) ────────── */
  // Descending sweep: E4 → C4 → G3
  window.playStartOverSound = function() {
    resume(); const t = ctx.currentTime;
    osc('sine', 330, 0.15, 0.10, t);
    osc('sine', 262, 0.13, 0.12, t + 0.08);
    osc('sine', 196, 0.11, 0.18, t + 0.17);
    noise(200, 0.15, 0.20, t + 0.12);
  };

  /* ── Generic UI click (all other buttons) ───── */
  // Tiny crisp tick
  window.playClickSound = function() {
    resume(); const t = ctx.currentTime;
    osc('sine', 880, 0.08, 0.04, t);
    noise(2000, 0.06, 0.03, t);
  };

  /* ── Open/close modal ───────────────────────── */
  window.playOpenSound = function() {
    resume(); const t = ctx.currentTime;
    osc('sine', 600, 0.10, 0.08, t);
    osc('sine', 800, 0.08, 0.10, t + 0.05);
  };
  window.playCloseSound = function() {
    resume(); const t = ctx.currentTime;
    osc('sine', 700, 0.09, 0.07, t);
    osc('sine', 500, 0.07, 0.10, t + 0.05);
  };

})();

// Global click sound — runs after DOM ready, bubble phase (doesn't interfere with onclick)
document.addEventListener('DOMContentLoaded', function() {
  document.addEventListener('click', function(e) {
    const btn = e.target.closest('button, .tab, .provider-card, .ai-status-pill, .grid-thumb, .pg-btn');
    if (!btn) return;
    // Skip buttons that have dedicated sounds (handled directly in their functions)
    const skip = ['btn-main', 'btn-keep', 'btn-del', 'btn-undo',
                   'prac-btn', 'welcome-btn-next', 'welcome-btn-back'];
    if (skip.some(cls => btn.classList.contains(cls))) return;
    playClickSound();
  });
});



