// INIT
// ══════════════════════════════════════════
(function init() {
  // Restore saved active provider
  const savedProvider = localStorage.getItem('fd_active_provider');
  if (savedProvider && PROVIDERS[savedProvider] && localStorage.getItem(PROVIDERS[savedProvider].storageKey)) {
    activeProvider = savedProvider;
  } else {
    // Fall back to first provider that has a key
    for (const id of Object.keys(PROVIDERS)) {
      if (localStorage.getItem(PROVIDERS[id].storageKey)) { activeProvider = id; break; }
    }
  }

  // Mark provider cards that have saved keys
  for (const id of Object.keys(PROVIDERS)) {
    if (localStorage.getItem(PROVIDERS[id].storageKey)) {
      const dot = document.getElementById('pdot-' + id);
      if (dot) dot.classList.add('has-key');
      const pc = document.getElementById('pcard-' + id);
      if (pc) pc.classList.add('has-key');
    }
  }

  updateStatusPill();
  updateActiveProviderSection();
})();

// ══════════════════════════════════════════
// THEME
// ══════════════════════════════════════════
function toggleTheme() {
  const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
  setTheme(isDark ? 'light' : 'dark');
}

(function initTheme() {
  const saved = localStorage.getItem('framedrop-theme');
  if (saved) {
    setTheme(saved);
  } else {
    const isDarkMode = window.matchMedia('(prefers-color-scheme: dark)').matches;
    if (isDarkMode) {
      setTheme('dark');
    } else {
      setTheme('light');
    }
    // Listen for live system theme changes when no manual preference is set
    window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', e => {
      if (!localStorage.getItem('framedrop-theme')) setTheme(e.matches ? 'dark' : 'light');
    });
  }
})();

function setTheme(t) {
  document.documentElement.setAttribute('data-theme', t);
  document.getElementById('theme-opt-light').classList.toggle('active', t === 'light');
  document.getElementById('theme-opt-dark').classList.toggle('active',  t === 'dark');
  localStorage.setItem('framedrop-theme', t);
}

// ══════════════════════════════════════════
// SETTINGS MODAL
// ══════════════════════════════════════════
function openSettings() {
  playOpenSound();
  document.getElementById('settings-overlay').classList.add('open');
  updateActiveProviderSection();
}
function closeSettings(e) {
  playCloseSound();
  if (e && e.target !== document.getElementById('settings-overlay')) return;
  document.getElementById('settings-overlay').classList.remove('open');
  selectedProviderInUI = null;
  document.getElementById('key-input-area').style.display = 'none';
  clearProviderActive();
}
function clearProviderActive() {
  document.querySelectorAll('.provider-card').forEach(c => c.classList.remove('active'));
}

function selectProvider(id) {
  selectedProviderInUI = id;
  clearProviderActive();
  const pc = document.getElementById('pcard-' + id);
  if (pc) pc.classList.add('active');

  const cfg = PROVIDERS[id];
  if (!cfg) return;

  document.getElementById('key-input-area').style.display = '';
  document.getElementById('key-input-title').textContent = cfg.inputTitle;

  const docsBtn = document.getElementById('key-docs-link');
  docsBtn.textContent = 'Get API key ↗';
  docsBtn.onclick = () => window.open(cfg.docsUrl, '_blank');

  const inp = document.getElementById('key-input');
  inp.placeholder = cfg.placeholder;
  inp.type = 'password';
  document.getElementById('key-eye-icon').className = 'ti ti-eye';

  const existing = localStorage.getItem(cfg.storageKey) || '';
  inp.value = existing ? maskKey(existing) : '';
  inp.dataset.realValue = existing;
  inp.dataset.dirty = 'false';
  inp.oninput = () => { inp.dataset.dirty = 'true'; };

  document.getElementById('azure-extras').style.display = id === 'azure' ? '' : 'none';
  if (id === 'azure') {
    document.getElementById('azure-endpoint').value   = localStorage.getItem('fd_azure_endpoint') || '';
    document.getElementById('azure-deployment').value = localStorage.getItem('fd_azure_deployment') || '';
  }

  document.getElementById('key-remove-btn').style.display = existing ? '' : 'none';
  document.getElementById('key-feedback').textContent = '';
  document.getElementById('key-feedback').className = 'key-feedback';

  // Show a note about CORS for local file usage
  const corsNote = document.getElementById('cors-note');
  if (corsNote) corsNote.style.display = '';
}

function maskKey(key) {
  if (key.length <= 8) return '••••••••';
  return key.slice(0, 6) + '••••••••' + key.slice(-4);
}

function toggleKeyVisibility() {
  const inp  = document.getElementById('key-input');
  const icon = document.getElementById('key-eye-icon');
  if (inp.type === 'password') {
    const real = inp.dataset.dirty === 'true' ? inp.value : (inp.dataset.realValue || inp.value);
    inp.value = real;
    inp.type = 'text';
    icon.className = 'ti ti-eye-off';
  } else {
    inp.type = 'password';
    icon.className = 'ti ti-eye';
  }
}

// ── Save key WITHOUT network verification (avoids CORS issues on file://) ──
function saveApiKey() {
  const id  = selectedProviderInUI;
  const cfg = PROVIDERS[id];
  if (!cfg) return;

  const inp = document.getElementById('key-input');
  let keyValue = inp.dataset.dirty === 'true' ? inp.value.trim() : inp.dataset.realValue;

  // If they typed a masked value and didn't change it, use the stored real value
  if (!keyValue || keyValue.includes('••')) {
    keyValue = inp.dataset.realValue;
  }

  if (!keyValue || keyValue.trim() === '') {
    setFeedback('Please paste your API key first.', 'error');
    return;
  }

  // Basic format checks per provider
  const formatError = checkKeyFormat(id, keyValue);
  if (formatError) {
    setFeedback(formatError, 'error');
    return;
  }

  if (id === 'azure') {
    const ep = document.getElementById('azure-endpoint').value.trim();
    const dp = document.getElementById('azure-deployment').value.trim();
    if (!ep || !dp) { setFeedback('Please fill in the endpoint URL and deployment name.', 'error'); return; }
    localStorage.setItem('fd_azure_endpoint',   ep);
    localStorage.setItem('fd_azure_deployment', dp);
  }

  // Save the key
  localStorage.setItem(cfg.storageKey, keyValue);
  activeProvider = id;
  localStorage.setItem('fd_active_provider', id);

  // Update UI
  const dot = document.getElementById('pdot-' + id);
  if (dot) dot.classList.add('has-key');
  const pcard = document.getElementById('pcard-' + id);
  if (pcard) pcard.classList.add('has-key');
  document.getElementById('key-remove-btn').style.display = '';

  inp.dataset.realValue = keyValue;
  inp.dataset.dirty = 'false';
  inp.value = maskKey(keyValue);
  inp.type = 'password';
  document.getElementById('key-eye-icon').className = 'ti ti-eye';

  setFeedback('✓ Key saved! AI analysis is now active. Optionally test the connection below.', 'success');
  updateStatusPill();
  updateActiveProviderSection();
  document.getElementById('key-test-btn').style.display = '';

  // Trigger analysis on current card if visible
  if (acw.style.display !== 'none' && idx < photos.length) {
    setTimeout(() => runAiAnalysis(photos[idx].url), 400);
  }
}

// ── Live connection test (optional, run after saving) ──
async function testConnection() {
  const id  = selectedProviderInUI || activeProvider;
  const cfg = PROVIDERS[id];
  if (!cfg) return;
  const key = localStorage.getItem(cfg.storageKey);
  if (!key) { setFeedback('Save a key first before testing.', 'error'); return; }

  const btn = document.getElementById('key-test-btn');
  btn.innerHTML = '<i class="ti ti-loader-2" style="animation:spin 0.8s linear infinite;display:inline-block;"></i> Testing…';
  btn.disabled = true;
  setFeedback('', '');

  try {
    let ok = false, statusCode = 0, errMsg = '';

    if (id === 'anthropic') {
      const r = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'x-api-key': key, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body: JSON.stringify({ model: 'claude-3-5-haiku-20241022', max_tokens: 5, messages: [{ role: 'user', content: 'Hi' }] })
      });
      statusCode = r.status;
      ok = r.status === 200 || r.status === 529; // 529 = overloaded but auth passed
      if (!ok) { const d = await r.json().catch(() => ({})); errMsg = d.error?.message || ('HTTP ' + r.status); }
    }

    else if (id === 'openai') {
      const r = await fetch('https://api.openai.com/v1/models', {
        headers: { 'Authorization': 'Bearer ' + key }
      });
      statusCode = r.status;
      ok = r.status === 200;
      if (!ok) { const d = await r.json().catch(() => ({})); errMsg = d.error?.message || ('HTTP ' + r.status); }
    }

    else if (id === 'google') {
      const r = await fetch('https://generativelanguage.googleapis.com/v1beta/models?key=' + key);
      statusCode = r.status;
      ok = r.status === 200;
      if (!ok) { const d = await r.json().catch(() => ({})); errMsg = d.error?.message || ('HTTP ' + r.status); }
    }

    else if (id === 'azure') {
      const ep = localStorage.getItem('fd_azure_endpoint') || '';
      const dp = localStorage.getItem('fd_azure_deployment') || '';
      const url = ep.replace(/\/$/, '') + '/openai/deployments/' + dp + '/chat/completions?api-version=2024-08-01-preview';
      const r = await fetch(url, {
        method: 'POST',
        headers: { 'api-key': key, 'content-type': 'application/json' },
        body: JSON.stringify({ messages: [{ role: 'user', content: 'Hi' }], max_tokens: 5 })
      });
      statusCode = r.status;
      ok = r.status === 200 || r.status === 400;
      if (!ok) { const d = await r.json().catch(() => ({})); errMsg = d.error?.message || ('HTTP ' + r.status); }
    }

    if (ok) {
      setFeedback('✓ Connection successful! ' + cfg.name + ' is responding correctly.', 'success');
    } else {
      // Give specific guidance based on status code
      let hint = '';
      if (statusCode === 401 || statusCode === 403) hint = 'The key was rejected (auth error). Double-check you copied it correctly.';
      else if (statusCode === 429) { ok = true; hint = 'Rate limited, but the key is valid!'; }
      else if (statusCode === 0)   hint = 'Network error — this may be a CORS issue when running from a local file. Try opening FrameDrop via a local server (e.g. VS Code Live Server) instead of double-clicking the HTML file.';
      else hint = errMsg || ('Unexpected response (HTTP ' + statusCode + ')');
      setFeedback((ok ? '✓ ' : '✗ ') + hint, ok ? 'success' : 'error');
    }
  } catch (err) {
    if (err.message.includes('Failed to fetch') || err.message.includes('NetworkError')) {
      setFeedback('✗ Network error — likely a CORS block when running from file://. Try a local server: in your framedrop folder run: npx serve . (requires Node.js)', 'error');
    } else {
      setFeedback('✗ Error: ' + err.message, 'error');
    }
  }

  btn.innerHTML = '<i class="ti ti-wifi"></i> Test connection';
  btn.disabled = false;
}

// ── Soft format validation (no network needed) ──
// NOTE: We skip strict prefix checks because key formats change.
// We just sanity-check length and obvious mistakes.
function checkKeyFormat(id, key) {
  if (key.length < 16) return 'This key looks too short — make sure you copied the entire key.';
  if (key.includes(' ')) return 'The key contains spaces — make sure you copied it without extra whitespace.';
  // Warn (not block) on known wrong-provider formats
  if (id === 'anthropic' && key.startsWith('sk-proj-')) {
    return 'This looks like an OpenAI key (starts with sk-proj-). Are you sure you selected the right provider?';
  }
  if (id === 'openai' && key.startsWith('sk-ant-')) {
    return 'This looks like an Anthropic key (starts with sk-ant-). Are you sure you selected the right provider?';
  }
  return null;
}

function removeApiKey() {
  const id  = selectedProviderInUI;
  const cfg = PROVIDERS[id];
  if (!cfg) return;
  if (!confirm('Remove the saved ' + cfg.name + ' API key?')) return;

  localStorage.removeItem(cfg.storageKey);
  if (id === 'azure') {
    localStorage.removeItem('fd_azure_endpoint');
    localStorage.removeItem('fd_azure_deployment');
  }

  const dot = document.getElementById('pdot-' + id);
  if (dot) dot.classList.remove('has-key');
  const pcard = document.getElementById('pcard-' + id);
  if (pcard) pcard.classList.remove('has-key');
  document.getElementById('key-remove-btn').style.display = 'none';
  document.getElementById('key-input').value = '';
  document.getElementById('key-input').dataset.realValue = '';

  if (activeProvider === id) {
    activeProvider = null;
    localStorage.removeItem('fd_active_provider');
    for (const pid of Object.keys(PROVIDERS)) {
      if (localStorage.getItem(PROVIDERS[pid].storageKey)) { activeProvider = pid; break; }
    }
    if (activeProvider) localStorage.setItem('fd_active_provider', activeProvider);
  }

  setFeedback('Key removed.', 'success');
  updateStatusPill();
  updateActiveProviderSection();
  if (acw.style.display !== 'none') showAiNoKey();
}

function deactivateProvider() {
  activeProvider = null;
  localStorage.removeItem('fd_active_provider');
  updateStatusPill();
  updateActiveProviderSection();
  if (acw.style.display !== 'none') showAiNoKey();
}

function setFeedback(msg, type) {
  const el = document.getElementById('key-feedback');
  el.textContent = msg;
  el.className = 'key-feedback ' + type;
}

function updateStatusPill() {
  const dot   = document.getElementById('ai-status-dot');
  const label = document.getElementById('ai-status-label');
  if (activeProvider) {
    dot.className     = 'ai-status-dot active';
    label.textContent = PROVIDERS[activeProvider].name + ' AI';
  } else {
    dot.className     = 'ai-status-dot';
    label.textContent = 'No AI';
  }
  const badge = document.getElementById('ai-provider-badge');
  if (badge) badge.textContent = activeProvider ? PROVIDERS[activeProvider].name : '—';
}

function updateActiveProviderSection() {
  const section = document.getElementById('active-provider-section');
  if (!activeProvider) { section.style.display = 'none'; return; }
  section.style.display = '';
  const cfg = PROVIDERS[activeProvider];
  document.getElementById('apc-name').textContent  = cfg.name;
  document.getElementById('apc-model').textContent = cfg.model;
}

// ══════════════════════════════════════════
// AI ANALYSIS
// ══════════════════════════════════════════
function showAiNoKey() {
  aiPanel.style.display   = '';
  aiNoKey.style.display   = 'flex';
  aiPrompt.style.display  = 'none';
  aiLoading.style.display = 'none';
  aiResult.style.display  = 'none';
}

// Show the analyze/skip prompt for a new photo
let pendingImageUrl = null;
function showAiPrompt(url) {
  if (!activeProvider) { showAiNoKey(); return; }
  pendingImageUrl = url;
  aiPanel.style.display   = '';
  aiNoKey.style.display   = 'none';
  aiPrompt.style.display  = '';
  aiLoading.style.display = 'none';
  aiResult.style.display  = 'none';
}

// User chose to use a credit
function approveAnalysis() {
  if (!pendingImageUrl) return;
  aiPrompt.style.display = 'none';
  runAiAnalysis(pendingImageUrl);
}

// User chose to skip
function skipAnalysis() {
  const savedUrl = pendingImageUrl; // keep reference for 'Analyze anyway'
  pendingImageUrl = null;
  aiPrompt.style.display = 'none';
  aiResult.style.display = '';
  aiResult.innerHTML = '<div class="ai-skipped"><span><i class="ti ti-player-skip-forward" style="margin-right:4px;"></i>Skipped — no credit used.</span><button id="analyze-anyway-btn">Analyze anyway</button></div>';
  const btn = document.getElementById('analyze-anyway-btn');
  if (btn) btn.addEventListener('click', () => {
    pendingImageUrl = savedUrl;
    aiResult.style.display = 'none';
    approveAnalysis();
  });
}

function toggleAiPanel() {
  aiOpen = !aiOpen;
  document.getElementById('ai-panel-body').style.display = aiOpen ? '' : 'none';
  aiChevron.className = aiOpen ? 'ti ti-chevron-up' : 'ti ti-chevron-down';
}

const AI_PROMPT = `You are a professional photo editor assistant. Analyze this photo for quality issues a photographer would care about when culling a shoot. Respond ONLY with valid JSON — no markdown, no backticks, no preamble. Format exactly:
{
  "sharpness":    { "score": 0-100, "label": "Tack sharp"|"Slightly soft"|"Blurry"|"Very blurry", "note": "brief note" },
  "exposure":     { "score": 0-100, "label": "Well exposed"|"Slightly over"|"Overexposed"|"Slightly under"|"Underexposed", "note": "brief note" },
  "glare":        { "score": 0-100, "label": "None"|"Slight"|"Moderate"|"Heavy", "note": "brief note" },
  "noise":        { "score": 0-100, "label": "Clean"|"Low noise"|"Noisy"|"Very noisy", "note": "brief note" },
  "composition":  { "score": 0-100, "label": "Strong"|"Good"|"Average"|"Weak", "note": "brief note" },
  "verdict":      "keep"|"delete"|"maybe",
  "summary":      "One sentence recommendation for the photographer."
}`;

async function runAiAnalysis(imageUrl) {
  if (!activeProvider) { showAiNoKey(); return; }

  aiPanel.style.display   = '';
  aiNoKey.style.display   = 'none';
  aiPrompt.style.display  = 'none';
  aiLoading.style.display = 'flex';
  aiResult.style.display  = 'none';
  aiResult.innerHTML = '';
  document.getElementById('ai-loading-label').textContent = 'Analyzing with ' + PROVIDERS[activeProvider].name + '…';

  if (aiAbortController) aiAbortController.abort();
  aiAbortController = new AbortController();
  const signal = aiAbortController.signal;

  const dot = document.getElementById('ai-status-dot');
  dot.className = 'ai-status-dot loading';

  try {
    const blob   = await fetch(imageUrl).then(r => r.blob());
    const base64 = await blobToBase64(blob);
    const mime   = blob.type || 'image/jpeg';
    if (signal.aborted) return;

    let parsed;
    if      (activeProvider === 'anthropic') parsed = await analyzeAnthropic(base64, mime, signal);
    else if (activeProvider === 'openai')    parsed = await analyzeOpenAI(base64, mime, signal);
    else if (activeProvider === 'google')    parsed = await analyzeGoogle(base64, mime, signal);
    else if (activeProvider === 'azure')     parsed = await analyzeAzure(base64, mime, signal);

    if (signal.aborted) return;
    dot.className = 'ai-status-dot active';
    renderAiResult(parsed);
  } catch (err) {
    if (err.name === 'AbortError') return;
    dot.className = 'ai-status-dot error';
    aiLoading.style.display = 'none';
    aiResult.style.display = '';

    // Give a helpful error message depending on likely cause
    let msg = err.message || 'Unknown error';
    let hint = '';
    if (msg.includes('401') || msg.includes('403') || msg.includes('invalid_api_key') || msg.includes('Unauthorized')) {
      hint = 'Your API key was rejected. Double-check it in <button onclick="openSettings()" class="link-btn">Settings</button>.';
    } else if (msg.includes('Failed to fetch') || msg.includes('NetworkError') || msg.includes('CORS')) {
      hint = 'Network error — this usually means a CORS restriction when opening the file directly. Try serving via a local server (see README) or check your internet connection.';
    } else if (msg.includes('429')) {
      hint = 'Rate limit hit — wait a moment and try again.';
    } else if (msg.includes('402') || msg.includes('insufficient_quota')) {
      hint = 'Your account is out of credits. Top up at the provider\'s website.';
    } else {
      hint = msg;
    }

    aiResult.innerHTML = `<div class="ai-error"><i class="ti ti-alert-circle"></i> <span>${hint}</span></div>`;
  }
}

// ── Anthropic ──
async function analyzeAnthropic(base64, mime, signal) {
  const key = localStorage.getItem(PROVIDERS.anthropic.storageKey);
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST', signal,
    headers: {
      'x-api-key': key,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true',
      'content-type': 'application/json'
    },
    body: JSON.stringify({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 800,
      messages: [{ role: 'user', content: [
        { type: 'image', source: { type: 'base64', media_type: mime, data: base64 } },
        { type: 'text', text: AI_PROMPT }
      ]}]
    })
  });
  if (!r.ok) {
    const body = await r.json().catch(() => ({}));
    throw new Error(r.status + ' — ' + (body.error?.message || r.statusText));
  }
  const d = await r.json();
  return parseJsonResponse(d.content.map(c => c.text || '').join(''));
}

// ── OpenAI ──
async function analyzeOpenAI(base64, mime, signal) {
  const key = localStorage.getItem(PROVIDERS.openai.storageKey);
  const r = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST', signal,
    headers: { 'Authorization': 'Bearer ' + key, 'content-type': 'application/json' },
    body: JSON.stringify({
      model: 'gpt-4o',
      max_tokens: 800,
      messages: [{ role: 'user', content: [
        { type: 'image_url', image_url: { url: 'data:' + mime + ';base64,' + base64, detail: 'high' } },
        { type: 'text', text: AI_PROMPT }
      ]}]
    })
  });
  if (!r.ok) {
    const body = await r.json().catch(() => ({}));
    throw new Error(r.status + ' — ' + (body.error?.message || r.statusText));
  }
  const d = await r.json();
  return parseJsonResponse(d.choices[0].message.content);
}

// ── Google Gemini ──
async function analyzeGoogle(base64, mime, signal) {
  const key = localStorage.getItem(PROVIDERS.google.storageKey);
  const r = await fetch(
    'https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=' + key,
    {
      method: 'POST', signal,
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [
          { inline_data: { mime_type: mime, data: base64 } },
          { text: AI_PROMPT }
        ]}],
        generationConfig: { maxOutputTokens: 800, temperature: 0.1 }
      })
    }
  );
  if (!r.ok) {
    const body = await r.json().catch(() => ({}));
    throw new Error(r.status + ' — ' + (body.error?.message || r.statusText));
  }
  const d = await r.json();
  return parseJsonResponse(d.candidates[0].content.parts[0].text);
}

// ── Azure OpenAI ──
async function analyzeAzure(base64, mime, signal) {
  const key = localStorage.getItem(PROVIDERS.azure.storageKey);
  const ep  = (localStorage.getItem('fd_azure_endpoint') || '').replace(/\/$/, '');
  const dp  = localStorage.getItem('fd_azure_deployment');
  const url = ep + '/openai/deployments/' + dp + '/chat/completions?api-version=2024-08-01-preview';
  const r = await fetch(url, {
    method: 'POST', signal,
    headers: { 'api-key': key, 'content-type': 'application/json' },
    body: JSON.stringify({
      max_tokens: 800,
      messages: [{ role: 'user', content: [
        { type: 'image_url', image_url: { url: 'data:' + mime + ';base64,' + base64, detail: 'high' } },
        { type: 'text', text: AI_PROMPT }
      ]}]
    })
  });
  if (!r.ok) {
    const body = await r.json().catch(() => ({}));
    throw new Error(r.status + ' — ' + (body.error?.message || r.statusText));
  }
  const d = await r.json();
  return parseJsonResponse(d.choices[0].message.content);
}

function parseJsonResponse(text) {
  const clean = text.replace(/```json|```/g, '').trim();
  try { return JSON.parse(clean); }
  catch (_) {
    const m = clean.match(/\{[\s\S]*\}/);
    if (m) return JSON.parse(m[0]);
    throw new Error('Could not parse AI response as JSON');
  }
}

function blobToBase64(blob) {
  return new Promise((res, rej) => {
    const r = new FileReader();
    r.onload  = () => res(r.result.split(',')[1]);
    r.onerror = () => rej(new Error('File read failed'));
    r.readAsDataURL(blob);
  });
}

function renderAiResult(d) {
  aiLoading.style.display = 'none';
  aiResult.style.display  = '';

  const metrics = [
    { key: 'sharpness',   label: 'Sharpness' },
    { key: 'exposure',    label: 'Exposure' },
    { key: 'glare',       label: 'Glare (lower = better)' },
    { key: 'noise',       label: 'Noise (lower = better)' },
    { key: 'composition', label: 'Composition' }
  ];
  const invertedKeys = new Set(['glare', 'noise']);

  let html = '<div class="ai-scores">';
  metrics.forEach(({ key, label }) => {
    const m = d[key]; if (!m) return;
    const raw = parseInt(m.score, 10) || 0;
    const pct = invertedKeys.has(key) ? 100 - raw : raw;
    const cls = pct >= 70 ? 'good' : pct >= 40 ? 'warn' : 'bad';
    html += `
      <div class="score-row">
        <div class="score-label-row">
          <span class="score-label" title="${m.note || ''}">${label}</span>
          <span class="score-value score-${cls}">${m.label}</span>
        </div>
        <div class="score-bar-bg">
          <div class="score-bar-fill bar-${cls}" style="width:${pct}%"></div>
        </div>
      </div>`;
  });
  html += '</div>';

  const vCls  = d.verdict === 'keep' ? 'verdict-keep' : d.verdict === 'delete' ? 'verdict-delete' : 'verdict-ok';
  const vIcon = d.verdict === 'keep' ? '✓ Keep' : d.verdict === 'delete' ? '✕ Consider deleting' : '⚡ Your call';
  html += `<div class="ai-verdict ${vCls}"><strong>${vIcon}:</strong> ${d.summary}</div>`;
  aiResult.innerHTML = html;
}

// ══════════════════════════════════════════
// TOOLTIP
// ══════════════════════════════════════════
function toggleTooltip(id) {
  document.getElementById(id).classList.toggle('open');
}

// ══════════════════════════════════════════
// ANIMATION HELPERS
// ══════════════════════════════════════════
function animateStat(id, newVal) {
  const el = document.getElementById(id);
  if (!el) return;
  const sp = el.querySelector('.stat-num');
  const target = sp || el;
  if (parseInt(target.textContent) === newVal) return; // no change, no roll
  target.classList.remove('stat-roll');
  void target.offsetWidth; // reflow
  target.textContent = newVal;
  target.classList.add('stat-roll');
  target.addEventListener('animationend', () => target.classList.remove('stat-roll'), { once: true });
}

function popInCard() {
  card.classList.remove('card-pop-in');
  void card.offsetWidth;
  card.classList.add('card-pop-in');
  card.addEventListener('animationend', () => card.classList.remove('card-pop-in'), { once: true });
}

// ══════════════════════════════════════════
// TAB SWITCHING
// ══════════════════════════════════════════
function switchTab(t) {
  document.getElementById('tab-del').classList.toggle('active',  t === 'del');
  document.getElementById('tab-keep').classList.toggle('active', t === 'keep');
  // Slide the underline
  const ul = document.getElementById('tab-underline');
  if (ul) ul.classList.toggle('to-keep', t === 'keep');
  delList.classList.toggle('hidden',  t !== 'del');
  keepList.classList.toggle('hidden', t !== 'keep');
  document.getElementById('del-footer').style.display   = t === 'del'  ? 'flex' : 'none';
  document.getElementById('keep-footer').style.display  = t === 'keep' ? 'flex' : 'none';
  document.getElementById('del-pagination').style.display  = (t === 'del'  && deleted.length > PER_PAGE) ? 'flex' : 'none';
  document.getElementById('keep-pagination').style.display = (t === 'keep' && kept.length > PER_PAGE) ? 'flex' : 'none';
}

// ══════════════════════════════════════════
// FILE LOADING
// ══════════════════════════════════════════
fi.addEventListener('change', e => loadFiles(Array.from(e.target.files)));
dz.addEventListener('dragover',  e => { e.preventDefault(); dz.classList.add('drag-over'); });
dz.addEventListener('dragleave', ()  => dz.classList.remove('drag-over'));
dz.addEventListener('drop', e => {
  e.preventDefault(); dz.classList.remove('drag-over');
  const files = Array.from(e.dataTransfer.files).filter(f =>
    f.type.startsWith('image/') || /\.(heic|raw|arw|cr2|nef|dng|orf|rw2)$/i.test(f.name)
  );
  if (files.length) loadFiles(files);
});

function loadFiles(files) {
  if (!files.length) return;
  photos = files.map(f => ({ file: f, url: URL.createObjectURL(f) }));
  idx = 0; deleted = []; kept = []; history = []; delPage = 1; keepPage = 1;
  delList.innerHTML  = '<div class="empty-pile">Nothing here yet</div>';
  keepList.innerHTML = '<div class="empty-pile">Nothing here yet</div>';
  updateBadges(); updateFooter();
  dz.style.display = 'none'; cs.style.display = 'block';
  doneScreen.style.display = 'none'; acw.style.display = 'block';
  showCard();
}

// ══════════════════════════════════════════
// CARD DISPLAY
// ══════════════════════════════════════════
function showCard() {
  if (idx >= photos.length) { showDone(); return; }
  const { file, url } = photos[idx];
  cardImg.src = url;
  cardName.textContent = file.name;
  cardSize.textContent = fmt(file.size);
  lKeep.style.opacity = 0; lDel.style.opacity = 0;
  bgCard.style.transform = 'scale(0.94) translateY(14px)';
  updateProgress(); resetDrag();
  popInCard();
  showAiPrompt(url);
}

function updateProgress() {
  const total = photos.length, done = idx;
  pFill.style.width = (total ? Math.round(done / total * 100) : 0) + '%';
  pText.textContent = done + ' of ' + total + ' reviewed';
  animateStat('stat-kept', kept.length);
  animateStat('stat-del',  deleted.length);
  animateStat('stat-rem',  total - done);
}

function updateBadges() {
  document.getElementById('del-count').textContent  = deleted.length;
  document.getElementById('keep-count').textContent = kept.length;
}

function updateFooter() {
  const hasDel  = deleted.length > 0;
  const hasKeep = kept.length > 0;
  document.getElementById('export-btn').style.display  = hasDel  ? '' : 'none';
  document.getElementById('script-wrap').style.display = hasDel  ? '' : 'none';
  document.getElementById('dl-all-btn').style.display  = hasKeep ? '' : 'none';
}

function fmt(b) {
  if (b < 1024) return b + ' B';
  if (b < 1048576) return Math.round(b / 1024) + ' KB';
  return (b / 1048576).toFixed(1) + ' MB';
}

// ══════════════════════════════════════════
// PAGINATED GRID
// ══════════════════════════════════════════
function renderGrid(list, items, page, type) {
  if (!items.length) { list.innerHTML = '<div class="empty-pile">Nothing here yet</div>'; return; }
  const total = Math.ceil(items.length / PER_PAGE);
  const pg    = Math.min(Math.max(page, 1), total);
  const slice = items.slice((pg - 1) * PER_PAGE, pg * PER_PAGE);

  const pgEl   = document.getElementById(type + '-pagination');
  const pgInfo = document.getElementById(type + '-pg-info');
  const pgPrev = document.getElementById(type + '-pg-prev');
  const pgNext = document.getElementById(type + '-pg-next');
  pgEl.style.display = items.length > PER_PAGE ? 'flex' : 'none';
  pgInfo.textContent = 'Page ' + pg + ' of ' + total;
  pgPrev.disabled    = pg <= 1;
  pgNext.disabled    = pg >= total;

  const grid = document.createElement('div');
  grid.className = 'photo-grid';
  slice.forEach(photo => {
    const cell = document.createElement('div');
    cell.className = 'grid-thumb';
    const safeName = photo.file.name.replace(/'/g, "&#39;");
    const dlBtn = type === 'keep'
      ? `<button class="thumb-dl" onclick="event.stopPropagation();dlOne('${photo.url}','${safeName}')" title="Download"><i class="ti ti-download"></i></button>`
      : '';
    cell.innerHTML = `<img src="${photo.url}" alt="${safeName}" loading="lazy"><div class="grid-thumb-overlay"><span class="thumb-name">${photo.file.name}</span>${dlBtn}</div>`;
    cell.addEventListener('click', () => openLightbox(photo.url));
    grid.appendChild(cell);
  });
  list.innerHTML = '';
  list.appendChild(grid);
}

function changePage(type, dir) {
  if (type === 'del') {
    delPage = Math.max(1, Math.min(delPage + dir, Math.ceil(deleted.length / PER_PAGE)));
    renderGrid(delList, deleted, delPage, 'del');
  } else {
    keepPage = Math.max(1, Math.min(keepPage + dir, Math.ceil(kept.length / PER_PAGE)));
    renderGrid(keepList, kept, keepPage, 'keep');
  }
}

// ══════════════════════════════════════════
// KEEP / DELETE
// ══════════════════════════════════════════
function animateSwipe(dir, cb) {
  if (animating) return; animating = true;
  card.classList.add(dir === 'right' ? 'anim-fly-right' : 'anim-fly-left');
  bgCard.classList.add('anim-bounce-in');
  setTimeout(() => {
    card.classList.remove('anim-fly-right', 'anim-fly-left');
    bgCard.classList.remove('anim-bounce-in');
    animating = false; cb();
  }, 370);
}

function doKeep() {
  if (idx >= photos.length || animating) return;
  playKeepSound();
  const photo = photos[idx]; lKeep.style.opacity = 1;
  animateSwipe('right', () => {
    history.push({ action: 'keep', photo, index: idx });
    kept.push(photo);
    keepPage = Math.ceil(kept.length / PER_PAGE);
    renderGrid(keepList, kept, keepPage, 'keep');
    idx++; updateBadges(); updateFooter(); showCard();
  });
}

function doDelete() {
  if (idx >= photos.length || animating) return;
  playDeleteSound();
  const photo = photos[idx]; lDel.style.opacity = 1;
  animateSwipe('left', () => {
    history.push({ action: 'delete', photo, index: idx });
    deleted.push(photo);
    delPage = Math.ceil(deleted.length / PER_PAGE);
    renderGrid(delList, deleted, delPage, 'del');
    idx++; updateBadges(); updateFooter(); showCard();
  });
}

function undoLast() {
  if (!history.length || animating) return;
  playUndoSound();
  const last = history.pop(); idx = last.index;
  if (last.action === 'delete') {
    deleted.pop(); renderGrid(delList, deleted, delPage, 'del');
  } else {
    kept.pop(); renderGrid(keepList, kept, keepPage, 'keep');
  }
  if (doneScreen.style.display !== 'none') {
    doneScreen.style.display = 'none'; acw.style.display = 'block';
  }
  updateBadges(); updateFooter(); showCard();
}

// ══════════════════════════════════════════
// DONE SCREEN
// ══════════════════════════════════════════
function showDone() {
  saveCurrentProject();
  if (aiAbortController) aiAbortController.abort();
  aiPanel.style.display   = 'none';
  aiPrompt.style.display  = 'none';
  pendingImageUrl = null;
  acw.style.display = 'none'; doneScreen.style.display = 'flex';
  document.getElementById('done-summary').textContent =
    'Kept ' + kept.length + ' photo' + (kept.length !== 1 ? 's' : '') +
    ', marked ' + deleted.length + ' for deletion.';
  updateProgress();
}

// ══════════════════════════════════════════
// LIGHTBOX
// ══════════════════════════════════════════
function openLightbox(url) {
  document.getElementById('lightbox-img').src = url;
  document.getElementById('lightbox').classList.add('open');
}
function closeLightbox() {
  document.getElementById('lightbox').classList.remove('open');
  document.getElementById('lightbox-img').src = '';
}

// ══════════════════════════════════════════
// DOWNLOADS
// ══════════════════════════════════════════
function dlOne(url, name) {
  const a = document.createElement('a'); a.href = url; a.download = name; a.click();
}

async function downloadAllKept() {
  playDownloadSound();
  if (!kept.length) return;
  if (typeof JSZip === 'undefined') { alert('JSZip not loaded — check your connection.'); return; }
  const btn = document.getElementById('dl-all-btn');
  const orig = btn.innerHTML;
  btn.innerHTML = '<i class="ti ti-loader-2" style="animation:spin 0.8s linear infinite;display:inline-block;"></i> Zipping…';
  btn.disabled = true;
  try {
    const zip = new JSZip();
    for (const p of kept) {
      const blob = await fetch(p.url).then(r => r.blob());
      zip.file(p.file.name, blob);
    }
    const zb = await zip.generateAsync({ type: 'blob', compression: 'DEFLATE', compressionOptions: { level: 6 } });
    const a  = document.createElement('a');
    a.href = URL.createObjectURL(zb);
    a.download = 'framedrop-kept-photos.zip';
    a.click();
  } catch(e) {
    alert('Error creating zip: ' + e.message);
  } finally {
    btn.innerHTML = orig; btn.disabled = false;
  }
}

function exportDeleteList() {
  playExportListSound();
  if (!deleted.length) return;
  dlText('# FrameDrop — photos marked for deletion\n# Generated: ' + new Date().toLocaleString() + '\n\n' +
    deleted.map(p => p.file.name).join('\n'), 'framedrop-delete-list.txt');
}

function exportShellScript() {
  playShellSound();
  if (!deleted.length) return;
  let s = '#!/bin/bash\n# FrameDrop — move deleted photos to a subfolder\n';
  s += '# Usage: cd into your photo folder, then run: bash framedrop-move-deleted.sh\n';
  s += '# Generated: ' + new Date().toLocaleString() + '\n\n';
  s += 'DEST="./FrameDrop_Deleted"\nmkdir -p "$DEST"\n\n';
  deleted.forEach(p => { s += 'mv "' + p.file.name.replace(/"/g, '\\"') + '" "$DEST/"\n'; });
  s += '\necho "Done — ' + deleted.length + ' photo(s) moved to $DEST"\n';
  s += 'open "$DEST" 2>/dev/null || xdg-open "$DEST" 2>/dev/null\n';
  dlText(s, 'framedrop-move-deleted.sh');
}

function dlText(c, n) {
  const a = document.createElement('a');
  a.href = URL.createObjectURL(new Blob([c], { type: 'text/plain' }));
  a.download = n; a.click();
}

// ══════════════════════════════════════════
// RESET
// ══════════════════════════════════════════
function resetApp() {
  playStartOverSound();
  if (aiAbortController) aiAbortController.abort();
  photos = []; idx = 0; deleted = []; kept = []; history = [];
  delPage = 1; keepPage = 1; animating = false;
  dz.style.display = ''; cs.style.display = 'none';
  doneScreen.style.display = 'none'; acw.style.display = 'none';
  aiPanel.style.display  = 'none';
  aiPrompt.style.display = 'none';
  pendingImageUrl = null;
  delList.innerHTML  = '<div class="empty-pile">Nothing here yet</div>';
  keepList.innerHTML = '<div class="empty-pile">Nothing here yet</div>';
  updateBadges(); updateFooter();
  ['stat-kept','stat-del','stat-rem'].forEach(id => { const el = document.getElementById(id); const sp = el.querySelector('.stat-num'); if (sp) sp.textContent = 0; else el.textContent = 0; });
  fi.value = '';
}


// ══════════════════════════════════════════
// PROJECTS
// ══════════════════════════════════════════
const PROJECTS_KEY = 'fd_projects';

function loadProjectsFromStorage() {
  try { return JSON.parse(localStorage.getItem(PROJECTS_KEY) || '[]'); }
  catch(e) { return []; }
}

function saveProjectsToStorage(projects) {
  localStorage.setItem(PROJECTS_KEY, JSON.stringify(projects));
}

function generateProjectId() {
  return 'proj_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);
}

// Save current session as a project (called from showDone)
function saveCurrentProject() {
  if (!photos.length) return;
  const projects = loadProjectsFromStorage();

  // Build a name from the first photo filename folder hint, or generic
  const firstName = photos[0].file.name.replace(/\.[^.]+$/, '');
  const suggestedName = firstName.length > 24 ? firstName.slice(0, 24) + '…' : firstName;

  const project = {
    id: generateProjectId(),
    name: suggestedName,
    createdAt: Date.now(),
    total: photos.length,
    keptNames:    kept.map(p => p.file.name),
    deletedNames: deleted.map(p => p.file.name),
    remaining:    photos.length - kept.length - deleted.length,
  };

  // Avoid exact duplicates (same files, same decisions) — update instead
  const existingIdx = projects.findIndex(p =>
    p.total === project.total &&
    JSON.stringify(p.keptNames) === JSON.stringify(project.keptNames) &&
    JSON.stringify(p.deletedNames) === JSON.stringify(project.deletedNames)
  );
  if (existingIdx >= 0) {
    projects[existingIdx] = { ...projects[existingIdx], ...project, id: projects[existingIdx].id };
  } else {
    projects.unshift(project);
  }

  saveProjectsToStorage(projects);
}

function openProjectsDrawer() {
  playOpenSound();
  document.getElementById('projects-drawer').classList.add('open');
  document.getElementById('projects-overlay').classList.add('open');
  renderProjectsList();
}

function closeProjectsDrawer() {
  playCloseSound();
  document.getElementById('projects-drawer').classList.remove('open');
  document.getElementById('projects-overlay').classList.remove('open');
}

function closeProjects(e) {
  if (e.target === document.getElementById('projects-overlay')) closeProjectsDrawer();
}

function renderProjectsList() {
  const projects = loadProjectsFromStorage();
  const list  = document.getElementById('projects-list');
  const empty = document.getElementById('projects-empty');
  const clearBtn = document.getElementById('projects-clear-btn');

  list.innerHTML = '';
  if (!projects.length) {
    empty.style.display = '';
    clearBtn.style.display = 'none';
    return;
  }
  empty.style.display = 'none';
  clearBtn.style.display = '';

  projects.forEach(proj => {
    const total    = proj.total || 0;
    const kept_n   = (proj.keptNames || []).length;
    const del_n    = (proj.deletedNames || []).length;
    const rem      = total - kept_n - del_n;
    const pct      = total ? Math.round((kept_n + del_n) / total * 100) : 0;
    const isDone   = rem <= 0;
    const date     = new Date(proj.createdAt).toLocaleDateString(undefined, { month:'short', day:'numeric', year:'numeric' });

    const card = document.createElement('div');
    card.className = 'project-card';
    card.innerHTML = `
      <div class="project-card-top">
        <div class="project-card-icon"><i class="ti ti-camera"></i></div>
        <div class="project-card-info">
          <div class="project-card-name" id="pname-${proj.id}" ondblclick="startRenameProject('${proj.id}')">${escHtml(proj.name)}</div>
          <div class="project-card-date">${date} · ${total} photos · ${pct}% reviewed</div>
        </div>
      </div>
      <div class="project-card-stats">
        <div class="proj-stat kept"><b>${kept_n}</b>Kept</div>
        <div class="proj-stat del"><b>${del_n}</b>Deleted</div>
        <div class="proj-stat rem"><b>${rem}</b>Remaining</div>
      </div>
      <div class="project-card-progress">
        <div class="project-card-progress-fill" style="width:${pct}%"></div>
      </div>
      <div class="project-card-actions">
        <button class="proj-action-btn" onclick="exportProjectDeleteList('${proj.id}')">
          <i class="ti ti-file-download"></i> Delete list
        </button>
        <button class="proj-action-btn" onclick="exportProjectShellScript('${proj.id}')">
          <i class="ti ti-terminal"></i> Shell script
        </button>
        <button class="proj-action-btn danger" onclick="deleteProject('${proj.id}')">
          <i class="ti ti-trash"></i>
        </button>
      </div>
    `;
    list.appendChild(card);
  });
}

function escHtml(str) {
  return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function startRenameProject(id) {
  const nameEl = document.getElementById('pname-' + id);
  if (!nameEl) return;
  const current = nameEl.textContent;
  const input = document.createElement('input');
  input.className = 'project-card-name-input';
  input.value = current;
  nameEl.replaceWith(input);
  input.focus(); input.select();
  function commit() {
    const newName = input.value.trim() || current;
    const projects = loadProjectsFromStorage();
    const proj = projects.find(p => p.id === id);
    if (proj) { proj.name = newName; saveProjectsToStorage(projects); }
    renderProjectsList();
  }
  input.addEventListener('blur', commit);
  input.addEventListener('keydown', e => { if (e.key === 'Enter') input.blur(); if (e.key === 'Escape') { input.value = current; input.blur(); } });
}

function deleteProject(id) {
  playClickSound();
  const projects = loadProjectsFromStorage().filter(p => p.id !== id);
  saveProjectsToStorage(projects);
  renderProjectsList();
}

function clearAllProjects() {
  if (!confirm('Delete all saved projects? This cannot be undone.')) return;
  playStartOverSound();
  localStorage.removeItem(PROJECTS_KEY);
  renderProjectsList();
}

function exportProjectDeleteList(id) {
  const projects = loadProjectsFromStorage();
  const proj = projects.find(p => p.id === id);
  if (!proj || !proj.deletedNames.length) { alert('No deleted photos in this project.'); return; }
  playExportListSound();
  dlText('# FrameDrop — photos marked for deletion\n# Project: ' + proj.name + '\n# Generated: ' + new Date().toLocaleString() + '\n\n' +
    proj.deletedNames.join('\n'), 'framedrop-delete-list.txt');
}

function exportProjectShellScript(id) {
  const projects = loadProjectsFromStorage();
  const proj = projects.find(p => p.id === id);
  if (!proj || !proj.deletedNames.length) { alert('No deleted photos in this project.'); return; }
  playShellSound();
  let s = '#!/bin/bash\n# FrameDrop — move deleted photos to a subfolder\n';
  s += '# Project: ' + proj.name + '\n';
  s += '# Generated: ' + new Date().toLocaleString() + '\n\n';
  s += 'DEST="./FrameDrop_Deleted"\nmkdir -p "$DEST"\n\n';
  proj.deletedNames.forEach(name => { s += 'mv "' + name.replace(/"/g, '\\"') + '" "$DEST/"\n'; });
  s += '\necho "Done — ' + proj.deletedNames.length + ' photo(s) moved to $DEST"\n';
  s += 'open "$DEST" 2>/dev/null || xdg-open "$DEST" 2>/dev/null\n';
  dlText(s, 'framedrop-move-deleted.sh');
}

// ══════════════════════════════════════════
// DRAG TO SWIPE
// ══════════════════════════════════════════
let dragX = 0, dragging = false, curX = 0;

function resetDrag() {
  card.style.transform = ''; card.style.transition = '';
  lKeep.style.opacity = 0; lDel.style.opacity = 0;
}

card.addEventListener('mousedown', e => {
  if (animating) return; dragging = true; dragX = e.clientX; card.style.transition = 'none';
});
document.addEventListener('mousemove', e => {
  if (!dragging) return;
  curX = e.clientX - dragX;
  card.style.transform = `translateX(${curX}px) rotate(${curX * 0.08}deg)`;
  lKeep.style.opacity = curX >  40 ? Math.min(1, (curX - 40) / 60)  : 0;
  lDel.style.opacity  = curX < -40 ? Math.min(1, (-curX - 40) / 60) : 0;
  const scale = 0.94 + Math.min(0.06, Math.abs(curX) / 800);
  const ty    = 14   - Math.min(14,   Math.abs(curX) / 8);
  bgCard.style.transform = `scale(${scale}) translateY(${ty}px)`;
});
document.addEventListener('mouseup', () => {
  if (!dragging) return; dragging = false;
  card.style.transition = 'transform 0.3s cubic-bezier(.4,0,.2,1)';
  if      (curX >  110) doKeep();
  else if (curX < -110) doDelete();
  else { resetDrag(); bgCard.style.transform = 'scale(0.94) translateY(14px)'; }
  curX = 0;
});

card.addEventListener('touchstart', e => {
  if (animating) return; dragX = e.touches[0].clientX; card.style.transition = 'none';
}, { passive: true });
card.addEventListener('touchmove', e => {
  curX = e.touches[0].clientX - dragX;
  card.style.transform = `translateX(${curX}px) rotate(${curX * 0.08}deg)`;
  lKeep.style.opacity = curX >  40 ? Math.min(1, (curX - 40) / 60)  : 0;
  lDel.style.opacity  = curX < -40 ? Math.min(1, (-curX - 40) / 60) : 0;
  const scale = 0.94 + Math.min(0.06, Math.abs(curX) / 800);
  bgCard.style.transform = `scale(${scale}) translateY(${14 - Math.min(14, Math.abs(curX) / 8)}px)`;
}, { passive: true });
card.addEventListener('touchend', () => {
  card.style.transition = 'transform 0.3s cubic-bezier(.4,0,.2,1)';
  if      (curX >  110) doKeep();
  else if (curX < -110) doDelete();
  else { resetDrag(); bgCard.style.transform = 'scale(0.94) translateY(14px)'; }
  curX = 0;
});

