// PRACTICE CULL (embedded in tutorial)
// ══════════════════════════════════════════

const PRACTICE_PHOTOS = [
  {
    src:      'data:image/jpeg;base64,',
    filename: 'Bad.JPG',
    correct:  'delete',
    ai: {
      sharpness:   { pct: 32, label: 'Blurry',        cls: 'bad'  },
      exposure:    { pct: 38, label: 'Overexposed',   cls: 'bad'  },
      glare:       { pct: 72, label: 'Heavy',         cls: 'bad'  },
      noise:       { pct: 55, label: 'Noisy',         cls: 'warn' },
      composition: { pct: 44, label: 'Average',       cls: 'warn' },
      verdict: 'delete',
      summary: 'Subject is distant and soft with heavy glare on the white plumage — consider deleting.'
    }
  },
  {
    src:      'data:image/jpeg;base64,',
    filename: 'Good.JPG',
    correct:  'keep',
    ai: {
      sharpness:   { pct: 91, label: 'Tack sharp',    cls: 'good' },
      exposure:    { pct: 83, label: 'Well exposed',  cls: 'good' },
      glare:       { pct: 12, label: 'None',          cls: 'good' },
      noise:       { pct: 18, label: 'Clean',         cls: 'good' },
      composition: { pct: 78, label: 'Strong',        cls: 'good' },
      verdict: 'keep',
      summary: 'Sharp detail on the heron, well-balanced exposure, striking red eye — a keeper.'
    }
  }
];

// Practice state machine
// Steps:
//   0 = show Bad photo, prompt DELETE
//   1 = Bad deleted -> show AI result, prompt UNDO
//   2 = Undone      -> show Bad again, prompt DELETE again
//   3 = Bad deleted (again) -> load Good, prompt KEEP
//   4 = Good kept   -> show AI result for Good -> done message
const PRACTICE_STEPS = [
  { photoIdx: 0, action: null,     inst: { icon:'del',  title:'Swipe left or click Delete', body:'This photo is soft and overexposed — it\'s a toss.' } },
  { photoIdx: 0, action: 'delete', inst: { icon:'undo', title:'Good call! Now try Undo',    body:'Changed your mind? Press the undo button to bring the photo back.' } },
  { photoIdx: 0, action: 'undo',   inst: { icon:'del',  title:'Delete it again',            body:'Yep — still a toss. Go ahead and delete it one more time.' } },
  { photoIdx: 1, action: 'delete', inst: { icon:'keep', title:'Now swipe right or click Keep', body:'This shot is sharp with great detail on the heron — it\'s a keeper.' } },
  { photoIdx: 1, action: 'keep',   inst: { icon:'done', title:'Practice complete! 🎉',      body:'You culled two photos, used undo, and kept the sharp shot. You\'re ready.' } },
];

let practiceStep = 0;
let practiceAnimating = false;

function initPractice() {
  practiceStep = 0;
  practiceAnimating = false;
  renderPracticeStep(false);
}

function renderPracticeStep(animated) {
  const step = PRACTICE_STEPS[practiceStep];
  const photo = PRACTICE_PHOTOS[step.photoIdx];
  const isLast = practiceStep === PRACTICE_STEPS.length - 1;

  // Image
  const img = document.getElementById('prac-img');
  if (img) {
    img.src = photo.src;
    img.alt = photo.filename;
  }
  const fn = document.getElementById('prac-filename');
  if (fn) fn.textContent = photo.filename;

  // Counter
  const ctr = document.getElementById('prac-counter');
  if (ctr) ctr.textContent = (step.photoIdx + 1) + ' / ' + PRACTICE_PHOTOS.length;

  // Labels hidden
  const lk = document.getElementById('prac-label-keep');
  const ld = document.getElementById('prac-label-del');
  if (lk) lk.style.opacity = 0;
  if (ld) ld.style.opacity = 0;

  // Instruction
  const inst = document.getElementById('prac-instruction');
  if (inst) {
    inst.style.opacity = '0';
    inst.className = 'practice-instruction';
    if (animated) {
      setTimeout(() => {
        inst.style.opacity = '';
        inst.classList.add('prac-slide-in');
      }, 180);
    } else {
      inst.style.opacity = '';
    }
    inst.innerHTML = `
      <div class="prac-inst-icon ${step.inst.icon}"><i class="ti ti-${
        step.inst.icon === 'del'  ? 'x' :
        step.inst.icon === 'keep' ? 'check' :
        step.inst.icon === 'undo' ? 'arrow-back-up' :
        'circle-check'
      }"></i></div>
      <div class="prac-inst-text">
        <strong>${step.inst.title}</strong>
        <span>${step.inst.body}</span>
      </div>`;
  }

  // AI result — show after action on each photo
  const aiEl = document.getElementById('prac-ai-result');
  // Show AI for step 1 (after Bad deleted) and step 4 (after Good kept)
  const showAi = practiceStep === 1 || practiceStep === 4;
  if (aiEl) {
    if (showAi) {
      const ai = photo.ai;
      const vCls = ai.verdict === 'keep' ? 'verdict-keep' : 'verdict-delete';
      const vIcon = ai.verdict === 'keep' ? '✓ Keep' : '✕ Consider deleting';
      const rows = [
        { label: 'Sharpness',   data: ai.sharpness   },
        { label: 'Exposure',    data: ai.exposure     },
        { label: 'Glare',       data: ai.glare        },
        { label: 'Noise',       data: ai.noise        },
        { label: 'Composition', data: ai.composition  },
      ];
      aiEl.style.display = '';
      aiEl.className = 'practice-ai-result prac-slide-in';
      aiEl.innerHTML = `
        <div class="prai-title"><i class="ti ti-sparkles"></i> Sample AI Analysis</div>
        <div class="prai-scores">
          ${rows.map(r => `
          <div class="prai-row">
            <span class="prai-label">${r.label}</span>
            <div class="prai-bar-bg"><div class="prai-bar-fill bar-${r.data.cls}" style="width:${r.data.pct}%"></div></div>
            <span class="prai-val score-${r.data.cls}">${r.data.label}</span>
          </div>`).join('')}
        </div>
        <div class="prai-verdict ai-verdict ${vCls}"><strong>${vIcon}:</strong> ${ai.summary}</div>`;
    } else {
      aiEl.style.display = 'none';
      aiEl.innerHTML = '';
    }
  }

  // Buttons
  const btnDel  = document.getElementById('prac-btn-del');
  const btnKeep = document.getElementById('prac-btn-keep');
  const btnUndo = document.getElementById('prac-btn-undo');

  if (btnDel && btnKeep && btnUndo) {
    if (isLast) {
      // All done — hide action buttons
      btnDel.style.display  = 'none';
      btnKeep.style.display = 'none';
      btnUndo.style.display = 'none';
    } else {
      const waiting = PRACTICE_STEPS[practiceStep].action;
      const needUndo  = waiting === 'delete' && practiceStep === 1; // after first delete
      const needDel   = waiting === null || waiting === 'undo';
      const needKeep  = waiting === 'delete' && practiceStep === 3;

      btnDel.style.display  = (!needKeep) ? '' : 'none';
      btnKeep.style.display = needKeep ? '' : 'none';
      btnUndo.style.display = needUndo ? '' : 'none';
      btnDel.disabled  = needUndo;   // dim delete while undo is the target
      btnKeep.disabled = false;
    }
  }

  // Progress dots
  for (let i = 0; i < 3; i++) {
    const dot = document.getElementById('ppd-' + i);
    if (!dot) continue;
    // dot 0 = step 0-1, dot 1 = step 2-3, dot 2 = step 4
    const dotStep = i === 0 ? 1 : i === 1 ? 3 : 4;
    dot.className = 'prac-prog-dot' +
      (practiceStep === dotStep ? ' active' : practiceStep > dotStep ? ' done' : '');
  }

  // Welcome next btn: disable while practice not done
  const nextBtn = document.getElementById('welcome-next-btn');
  if (nextBtn) {
    nextBtn.disabled = !isLast;
    nextBtn.style.opacity = isLast ? '' : '0.4';
  }
}

function practiceAnimateCard(dir, cb) {
  if (practiceAnimating) return;
  practiceAnimating = true;
  const card = document.getElementById('prac-card');
  const bg   = document.getElementById('prac-bg-card');
  card.classList.add(dir === 'right' ? 'prac-fly-right' : 'prac-fly-left');
  if (bg) bg.classList.add('prac-bounce-in');
  setTimeout(() => {
    card.classList.remove('prac-fly-right', 'prac-fly-left');
    if (bg) bg.classList.remove('prac-bounce-in');
    practiceAnimating = false;
    cb();
  }, 340);
}

function practiceDelete() {
  if (practiceAnimating) return;
  const ld = document.getElementById('prac-label-del');
  if (ld) ld.style.opacity = 1;
  if (practiceStep === 0) {
    // First delete of Bad photo
    practiceAnimateCard('left', () => {
      practiceStep = 1;
      renderPracticeStep(true);
    });
  } else if (practiceStep === 2) {
    // Second delete of Bad photo after undo
    practiceAnimateCard('left', () => {
      practiceStep = 3;
      renderPracticeStep(true);
    });
  }
}

function practiceKeep() {
  if (practiceAnimating) return;
  if (practiceStep !== 3) return;
  const lk = document.getElementById('prac-label-keep');
  if (lk) lk.style.opacity = 1;
  practiceAnimateCard('right', () => {
    practiceStep = 4;
    renderPracticeStep(true);
  });
}

function practiceUndo() {
  if (practiceAnimating || practiceStep !== 1) return;
  // Snap card back in from left
  const card = document.getElementById('prac-card');
  card.style.animation = 'none';
  card.style.transform = 'translateX(-400px) rotate(-18deg)';
  card.style.opacity   = '0';
  requestAnimationFrame(() => {
    card.style.transition = 'transform 0.32s cubic-bezier(.34,1.2,.64,1), opacity 0.2s';
    card.style.transform  = '';
    card.style.opacity    = '';
    setTimeout(() => { card.style.transition = ''; }, 350);
  });
  practiceStep = 2;
  renderPracticeStep(true);
}

// Drag-to-swipe on practice card
(function initPracticeDrag() {
  let dragX = 0, dragging = false, curX = 0;
  const card = document.getElementById('prac-card');
  if (!card) return;

  function resetPracDrag() {
    card.style.transform = '';
    card.style.transition = '';
    const lk = document.getElementById('prac-label-keep');
    const ld = document.getElementById('prac-label-del');
    if (lk) lk.style.opacity = 0;
    if (ld) ld.style.opacity = 0;
  }

  card.addEventListener('mousedown', e => { if (practiceAnimating) return; dragging = true; dragX = e.clientX; card.style.transition = 'none'; });
  document.addEventListener('mousemove', e => {
    if (!dragging) return;
    curX = e.clientX - dragX;
    card.style.transform = `translateX(${curX}px) rotate(${curX * 0.08}deg)`;
    const lk = document.getElementById('prac-label-keep');
    const ld = document.getElementById('prac-label-del');
    if (lk) lk.style.opacity = curX >  35 ? Math.min(1,(curX-35)/50) : 0;
    if (ld) ld.style.opacity = curX < -35 ? Math.min(1,(-curX-35)/50) : 0;
    const bg = document.getElementById('prac-bg-card');
    if (bg) bg.style.transform = `scale(${0.94 + Math.min(0.06,Math.abs(curX)/700)}) translateY(${14-Math.min(14,Math.abs(curX)/7)}px)`;
  });
  document.addEventListener('mouseup', () => {
    if (!dragging) return; dragging = false;
    card.style.transition = 'transform 0.28s cubic-bezier(.4,0,.2,1)';
    if      (curX >  90) practiceKeep();
    else if (curX < -90) practiceDelete();
    else { resetPracDrag(); const bg = document.getElementById('prac-bg-card'); if (bg) bg.style.transform = 'scale(0.94) translateY(10px)'; }
    curX = 0;
  });

  card.addEventListener('touchstart', e => { if (practiceAnimating) return; dragX = e.touches[0].clientX; card.style.transition = 'none'; }, {passive:true});
  card.addEventListener('touchmove', e => {
    curX = e.touches[0].clientX - dragX;
    card.style.transform = `translateX(${curX}px) rotate(${curX*0.08}deg)`;
    const lk = document.getElementById('prac-label-keep');
    const ld = document.getElementById('prac-label-del');
    if (lk) lk.style.opacity = curX >  35 ? Math.min(1,(curX-35)/50) : 0;
    if (ld) ld.style.opacity = curX < -35 ? Math.min(1,(-curX-35)/50) : 0;
  }, {passive:true});
  card.addEventListener('touchend', () => {
    card.style.transition = 'transform 0.28s cubic-bezier(.4,0,.2,1)';
    if      (curX >  90) practiceKeep();
    else if (curX < -90) practiceDelete();
    else { card.style.transform = ''; }
    curX = 0;
  });
})();
